{"title": "RFC 7231 Allow header violation: only first partial match's methods reported", "description": "When multiple routes match the same path with different methods (e.g., Route('/items', ..., methods=['GET']) and Route('/items', ..., methods=['POST'])), the router only stores the first partial match (`partial is None` guard). The 405 Allow header only lists that first route's methods, not all methods supported by the resource. RFC 7231 §6.5.5 requires 'a list of the target resource's currently supported methods.'", "severity": "P1", "old_string": "        partial = None
        for route in self.routes:
            match, child_scope = route.matches(scope)
            if match == Match.FULL:
                scope.update(child_scope)
                await route.handle(scope, receive, send)
                return
            elif match == Match.PARTIAL and partial is None:
                partial = route
                partial_scope = child_scope

        if partial is not None:
            scope.update(partial_scope)
            await partial.handle(scope, receive, send)
            return", "new_string": "        partial = None
        partial_allowed_methods = set()
        for route in self.routes:
            match, child_scope = route.matches(scope)
            if match == Match.FULL:
                scope.update(child_scope)
                await route.handle(scope, receive, send)
                return
            elif match == Match.PARTIAL:
                if partial is None:
                    partial = route
                    partial_scope = child_scope
                if hasattr(route, "methods") and route.methods:
                    partial_allowed_methods.update(route.methods)

        if partial is not None:
            if partial_allowed_methods and hasattr(partial, "methods"):
                partial.methods = partial_allowed_methods
            scope.update(partial_scope)
            await partial.handle(scope, receive, send)
            return", "invariant": "HTTP 405 responses MUST include an Allow header listing ALL methods the target resource supports (RFC 7231 §6.5.5)"}
